{
  "permissions": {
    "allow": [
      "Bash(swift run *)",
      "Bash(swift test *)",
      "Bash(entire *)",
      "WebFetch(domain:docs.entire.io)",
      "Bash(brew info *)",
      "Bash(chmod +x *)",
      "Bash(swift package *)",
      "Bash(ARCHON_SUPPRESS_NESTED_CLAUDE_WARNING=1 archon *)",
      "Bash(archon *)",
      "mcp__plugin_serena_serena__get_symbols_overview",
      "mcp__plugin_serena_serena__activate_project",
      "mcp__plugin_serena_serena__read_file",
      "mcp__plugin_serena_serena__list_dir",
      "mcp__plugin_serena_serena__find_symbol",
      "mcp__plugin_serena_serena__search_for_pattern"
    ],
    "deny": [
      "Read(./.entire/metadata/**)"
    ]
  },
  "hooks": {
    "PostToolUse": [
      {
        "matcher": "Task",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code post-task"
          }
        ]
      },
      {
        "matcher": "TodoWrite",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code post-todo"
          }
        ]
      }
    ],
    "PreToolUse": [
      {
        "matcher": "Task",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code pre-task"
          }
        ]
      }
    ],
    "SessionEnd": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code session-end"
          }
        ]
      }
    ],
    "SessionStart": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code session-start"
          }
        ]
      }
    ],
    "Stop": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code stop"
          },
          {
            "type": "command",
            "command": "npx @fcamblor/gitdiff-watcher@0.2.0 --on '**/CLAUDE.md' --files-separator ',' --exec '.claude/scripts/check-claude-md-lines.sh {{ON_CHANGES_RUN_CHANGED_FILES}}'",
            "timeout": 10,
            "statusMessage": "Checking CLAUDE.md file sizes..."
          },
          {
            "type": "command",
            "command": "npx @fcamblor/gitdiff-watcher@0.2.0 --on 'AIUsagesTrackers/Sources/**/*.swift' --on 'AIUsagesTrackers/Package.swift' --exec 'cd AIUsagesTrackers && swift build'",
            "timeout": 180,
            "statusMessage": "Building Swift package (incl. SwiftLint)..."
          },
          {
            "type": "command",
            "command": "npx @fcamblor/gitdiff-watcher@0.2.0 --on 'AIUsagesTrackers/Sources/**/*.swift' --on 'AIUsagesTrackers/Tests/**/*.swift' --on 'AIUsagesTrackers/Package.swift' --exec 'cd AIUsagesTrackers && swift test'",
            "timeout": 180,
            "statusMessage": "Running Swift tests..."
          },
          {
            "type": "command",
            "command": "npx @fcamblor/gitdiff-watcher@0.2.0 --on 'AIUsagesTrackers/Package.swift' --exec 'cd AIUsagesTrackers && swift package describe > /dev/null'",
            "timeout": 30,
            "statusMessage": "Validating Package.swift..."
          }
        ]
      }
    ],
    "UserPromptSubmit": [
      {
        "matcher": "",
        "hooks": [
          {
            "type": "command",
            "command": "entire hooks claude-code user-prompt-submit"
          }
        ]
      }
    ]
  },
  "enabledPlugins": {
    "impeccable@impeccable": true
  }
}

